'use client';

import React, { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';

/**
 * CountUp Component
 * Animates a number from 0 to target value with easing
 * 
 * @param {number} end - Target number to count to
 * @param {number} duration - Animation duration in milliseconds
 * @param {boolean} isPercentage - Whether to show % symbol
 * @param {boolean} start - Trigger to start animation
 */
const CountUp = ({ end, duration = 2000, isPercentage = false, start = false }) => {
  const [count, setCount] = useState(0);
  const countRef = useRef(0);
  const startTimeRef = useRef(null);
  const animationFrameRef = useRef(null);

  // Easing function for smooth animation (easeOutExpo)
  const easeOutExpo = (t) => {
    return t === 1 ? 1 : 1 - Math.pow(2, -10 * t);
  };

  useEffect(() => {
    if (!start) return;

    // Reset values when starting
    countRef.current = 0;
    startTimeRef.current = null;

    const animate = (currentTime) => {
      if (!startTimeRef.current) {
        startTimeRef.current = currentTime;
      }

      const elapsed = currentTime - startTimeRef.current;
      const progress = Math.min(elapsed / duration, 1);
      
      // Apply easing function
      const easedProgress = easeOutExpo(progress);
      const currentCount = Math.floor(easedProgress * end);
      
      countRef.current = currentCount;
      setCount(currentCount);

      if (progress < 1) {
        animationFrameRef.current = requestAnimationFrame(animate);
      } else {
        // Ensure we hit the exact target
        setCount(end);
      }
    };

    animationFrameRef.current = requestAnimationFrame(animate);

    // Cleanup function
    return () => {
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }
    };
  }, [end, duration, start]);

  return (
    <span className="tabular-nums">
      {count}
      {isPercentage && '%'}
    </span>
  );
};

/**
 * StatCard Component
 * Individual stat display with icon, number, and label
 */
const StatCard = ({ number, label, isPercentage = false, start, delay = 0 }) => {
  return (
    <motion.div
      className="flex flex-col items-center justify-center p-6 sm:p-8"
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{
        duration: 0.6,
        delay: delay,
        type: "spring",
        stiffness: 100,
        damping: 15
      }}
    >
      {/* Counter Number */}
      <div className="text-4xl sm:text-5xl md:text-6xl lg:text-7xl font-bold bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 bg-clip-text text-transparent">
        <CountUp 
          end={number} 
          duration={2500} 
          isPercentage={isPercentage}
          start={start}
        />
      </div>
      
      {/* Label */}
      <div className="mt-2 sm:mt-3 text-sm sm:text-base md:text-lg font-medium text-gray-300 tracking-wide">
        {label}
      </div>
    </motion.div>
  );
};

/**
 * StatsCounter Component
 * Main component that displays all statistics with count-up animation
 * Triggers animation when section enters viewport
 */
const StatsCounter = () => {
  const [startCounting, setStartCounting] = useState(false);
  const sectionRef = useRef(null);

  useEffect(() => {
    // Create intersection observer to detect when section is visible
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          // Start counting when section is 20% visible
          if (entry.isIntersecting && entry.intersectionRatio >= 0.2) {
            setStartCounting(true);
            // Disconnect observer after triggering once
            observer.disconnect();
          }
        });
      },
      {
        threshold: [0, 0.2, 0.5, 1], // Multiple thresholds for better detection
        rootMargin: '0px'
      }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    // Cleanup
    return () => {
      if (sectionRef.current) {
        observer.unobserve(sectionRef.current);
      }
    };
  }, []);

  // Stats data configuration
  const stats = [
    { number: 113, label: 'Projects', isPercentage: false, delay: 0 },
    { number: 100, label: 'Clients', isPercentage: false, delay: 0.1 },
    { number: 96, label: 'Success Rate', isPercentage: true, delay: 0.2 }
  ];

  return (
    <section 
      ref={sectionRef}
      className="w-full bg-black py-12 sm:py-16 md:py-20 lg:py-24 px-4 sm:px-6 lg:px-8"
    >
      <div className="max-w-7xl mx-auto">
        {/* Optional Section Title */}
        <motion.div
          className="text-center mb-8 sm:mb-12 md:mb-16"
          initial={{ opacity: 0, y: -20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
        >
          <h2 className="text-3xl sm:text-4xl md:text-5xl font-bold text-white mb-3 sm:mb-4">
            Our Impact in Numbers
          </h2>
          <p className="text-sm sm:text-base md:text-lg text-gray-400 max-w-2xl mx-auto">
            Trusted by businesses worldwide to deliver exceptional results
          </p>
        </motion.div>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 sm:gap-6 md:gap-8 lg:gap-12">
          {stats.map((stat, index) => (
            <StatCard
              key={stat.label}
              number={stat.number}
              label={stat.label}
              isPercentage={stat.isPercentage}
              start={startCounting}
              delay={stat.delay}
            />
          ))}
        </div>

        {/* Decorative Elements */}
        <div className="relative mt-12 sm:mt-16">
          <div className="absolute inset-0 flex items-center" aria-hidden="true">
            <div className="w-full border-t border-gray-800"></div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default StatsCounter;
